+import { PRODUCTS_PER_PAGE } from "@/lib/constants";
+import { shopifyFetch } from "./storefront";
+import {
+  GET_PRODUCTS_QUERY,
+  GET_PRODUCT_BY_HANDLE_QUERY,
+  GET_COLLECTIONS_QUERY,
+  GET_COLLECTION_BY_HANDLE_QUERY,
+  CREATE_CART_MUTATION,
+  ADD_TO_CART_MUTATION,
