+/** Shopify Storefront API GraphQL queries */
+
+const PRODUCT_FRAGMENT = `
+  fragment ProductFields on Product {
+    id
+    handle
+    title
+    description
+    descriptionHtml
+    vendor
+    productType
+    tags
+    availableForSale
+    featuredImage {
+      url
+      altText
+      width
+      height
+    }
+    images(first: 10) {
+      edges {
+        node {
+          url
+          altText
+          width
+          height
+        }
+      }
+    }
+    variants(first: 50) {
+      edges {
+        node {
+          id
+          title
+          availableForSale
+          price {
+            amount
+            currencyCode
+          }
+          compareAtPrice {
+            amount
+            currencyCode
+          }
+          image {
+            url
+            altText
+            width
+            height
+          }
+          selectedOptions {
+            name
+            value
+          }
+        }
+      }
+    }
+    priceRange {
+      minVariantPrice {
+        amount
+        currencyCode
+      }
+      maxVariantPrice {
+        amount
+        currencyCode
+      }
+    }
+    compareAtPriceRange {
+      minVariantPrice {
+        amount
+        currencyCode
+      }
+    }
+  }
+`;
+
+export const GET_PRODUCTS_QUERY = `
+  ${PRODUCT_FRAGMENT}
+  query GetProducts($first: Int!) {
+    products(first: $first) {
